15	    } @else if (playlistType === 'stalker') {
16	        <app-stalker-portal-import (addClicked)="closeDialog()" />
17	    } @else if (playlistType === 'xtream') {
18	        <app-xtream-code-import (addClicked)="closeDialog()" />
