                            this.translate.instant(
                                'HOME.PLAYLISTS.REFRESH_XTREAM_DIALOG.ERROR'
                            ),
                            undefined,
                            { duration: 3000 }
                        );
                    }
                } finally {
                    this.clearBusyOperation(item._id);
                    this.setPendingRefresh(item._id, false);
                }
            },
        });
    }

