import { expect, test } from '@playwright/test';
import { join } from 'path';

const fixturePath = join(__dirname, 'fixtures/test.m3u');

test('basic test', async ({ page }) => {
    await page.goto('/');

    // Basic checks
    expect(await page.title()).toBe('IPTVnator');

    // Upload playlist test
